module RefModule( clock, reset, count );input clock;
	input reset;
	output [2:0] count; 
	reg [2:0] count; 

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or  posedge reset or posedge dbg_halt) 
	begin 
		if  (reset) 
			count = 0;   
		else if  ( count < 3'b111 )  
			count = count + 1;   
		else 
			count = 0;   
	end 
endmodule
